const fs = require('fs-extra');
const path = require('path');

const {
    command,
    query,
    subscription,
    createOps,
    createIsolationMessage,
    createIsolationStub,
    materializeApi,
    createCompatApi,
    exposeRoleApis,
} = require('../../src/preloads/shared/apiFactory');
const {
    createCatalog,
    createShellCatalog,
    createSessionCatalog,
    createContentCatalog,
} = require('../../src/preloads/shared/catalog');
const { bootstrapPreload } = require('../../src/preloads/shared/bootstrap');
const { LITE_KEYS, ROLE_API_NAMES, VIEWER_KEYS } = require('../../src/preloads/shared/roles');

const REPO_ROOT = path.resolve(__dirname, '..', '..');
const RUNTIME_DIR = path.join(REPO_ROOT, 'src', 'preloads', 'runtime');

function serializeFunction(fn) {
    return fn.toString();
}

function buildBundleSource({ role, apiName, allowedKeys }) {
    return `// Auto-generated by scripts/build-preloads.js. Do not edit directly.
const { contextBridge, ipcRenderer, webUtils } = require('electron');

${serializeFunction(command)}

${serializeFunction(query)}

${serializeFunction(subscription)}

${serializeFunction(createOps)}

${serializeFunction(materializeApi)}

${serializeFunction(createIsolationMessage)}

${serializeFunction(createIsolationStub)}

${serializeFunction(createCompatApi)}

${serializeFunction(exposeRoleApis)}

${serializeFunction(createShellCatalog)}

${serializeFunction(createSessionCatalog)}

${serializeFunction(createContentCatalog)}

${serializeFunction(createCatalog)}

${serializeFunction(bootstrapPreload)}

const ROLE_API_NAME = ${JSON.stringify(apiName)};
const ALLOWED_KEYS = ${JSON.stringify(allowedKeys, null, 4)};

try {
    bootstrapPreload({
        apiName: ROLE_API_NAME,
        allowedKeys: ALLOWED_KEYS,
    });
    console.log('[Preload][${role}] loaded via runtime bundle');
} catch (error) {
    console.error('[Preload][${role}] failed to initialize runtime bundle:', error);
    throw error;
}
`;
}

async function buildPreloadBundles() {
    await fs.ensureDir(RUNTIME_DIR);

    const targets = [
        {
            role: 'lite',
            apiName: ROLE_API_NAMES.lite,
            allowedKeys: LITE_KEYS,
            filePath: path.join(RUNTIME_DIR, 'lite.bundle.js'),
        },
        {
            role: 'viewer',
            apiName: ROLE_API_NAMES.viewer,
            allowedKeys: VIEWER_KEYS,
            filePath: path.join(RUNTIME_DIR, 'viewer.bundle.js'),
        },
    ];

    for (const target of targets) {
        const source = buildBundleSource(target);
        await fs.writeFile(target.filePath, source, 'utf8');
    }

    return targets.map(({ role, filePath }) => ({ role, filePath }));
}

module.exports = {
    RUNTIME_DIR,
    buildBundleSource,
    buildPreloadBundles,
};
